83	pub fn make_parser_for(lang: Lang) -> tree_sitter::Parser {
84	    let mut parser = tree_sitter::Parser::new();
85	    let language: tree_sitter::Language = match lang {
86	        Lang::Rust => tree_sitter_rust::LANGUAGE.into(),
87	        Lang::JavaScript => tree_sitter_javascript::LANGUAGE.into(),
88	        Lang::TypeScript => tree_sitter_typescript::LANGUAGE_TYPESCRIPT.into(),
89	        Lang::Tsx => tree_sitter_typescript::LANGUAGE_TSX.into(),
90	        Lang::Python => tree_sitter_python::LANGUAGE.into(),
91	    };
92	    parser
93	        .set_language(&language)
94	        .expect("failed to load grammar");
95	    parser
96	}
