111	pub fn parse_source_tree_for(source: &str, lang: Lang) -> Result<tree_sitter::Tree, &'static str> {
112	    let tree = make_parser_for(lang)
113	        .parse(source, None)
114	        .ok_or("parse returned None")?;
115	    if tree.root_node().has_error() {
116	        return Err("parse error");
117	    }
118	    Ok(tree)
119	}
