155	fn extract_rust_functions(
156	    node: tree_sitter::Node,
157	    source: &str,
158	    file: &str,
159	    functions: &mut Vec<FunctionInfo>,
160	) {
161	    match node.kind() {
162	        "function_item" => {
163	            functions.push(make_function_info(node, source, file, &RUST_CONFIG));
164	        }
165	        "let_declaration" => {
166	            extract_rust_let_declaration(node, source, file, functions);
167	        }
168	        _ => {
169	            for child in children_of(node) {
170	                extract_rust_functions(child, source, file, functions);
171	            }
172	        }
173	    }
174	}
