185	fn extract_rust_let_declaration(
186	    node: tree_sitter::Node,
187	    source: &str,
188	    file: &str,
189	    functions: &mut Vec<FunctionInfo>,
190	) {
191	    if let Some(val) = find_child_by_field(node, "value")
192	        && val.kind() == "closure_expression"
193	    {
194	        functions.push(make_function_info(node, source, file, &RUST_CONFIG));
195	    }
196	    for child in children_of(node) {
197	        if child.kind() != "closure_expression" {
198	            extract_rust_functions(child, source, file, functions);
199	        }
200	    }
201	}
