203	fn extract_python_functions(
204	    node: tree_sitter::Node,
205	    source: &str,
206	    file: &str,
207	    config: &LangConfig,
208	    functions: &mut Vec<FunctionInfo>,
209	) {
210	    match node.kind() {
211	        "function_definition" | "decorated_definition" => {
212	            let fn_node = if node.kind() == "decorated_definition" {
213	                children_of(node)
214	                    .into_iter()
215	                    .find(|c| c.kind() == "function_definition" || c.kind() == "class_definition")
216	                    .unwrap_or(node)
217	            } else {
218	                node
219	            };
220	            if fn_node.kind() == "function_definition" {
221	                functions.push(make_function_info(fn_node, source, file, config));
222	            } else {
223	                for child in children_of(fn_node) {
224	                    extract_python_functions(child, source, file, config, functions);
225	                }
226	            }
227	        }
228	        "class_definition" => {
229	            for child in children_of(node) {
230	                if child.kind() == "block" {
231	                    for class_child in children_of(child) {
232	                        extract_python_functions(class_child, source, file, config, functions);
233	                    }
234	                }
235	            }
236	        }
237	        _ => {
238	            for child in children_of(node) {
239	                extract_python_functions(child, source, file, config, functions);
240	            }
241	        }
242	    }
243	}
