342	pub fn find_child_by_field<'a>(
343	    node: tree_sitter::Node<'a>,
344	    field: &str,
345	) -> Option<tree_sitter::Node<'a>> {
346	    let mut cursor = node.walk();
347	    for child in node.children(&mut cursor) {
348	        if child.kind() == field {
349	            return Some(child);
350	        }
351	    }
352	    node.child_by_field_name(field)
