355	pub fn make_function_info(
356	    node: tree_sitter::Node,
357	    source: &str,
358	    file: &str,
359	    config: &LangConfig,
360	) -> FunctionInfo {
361	    let start_line = node.start_position().row + 1;
362	    let end_line = node.end_position().row + 1;
363	    let hashes = collect_subtree_hashes(node, source, config);
364	    FunctionInfo {
365	        file: file.to_string(),
366	        start_line,
367	        end_line,
368	        node_hashes: hashes,
369	    }
370	}
