372	fn normalize_node_text(node: tree_sitter::Node, source: &str, config: &LangConfig) -> String {
373	    let kind = node.kind();
374	    if config.identifier_kinds.contains(&kind) {
375	        return "_ID".to_string();
376	    }
377	    if config.literal_kinds.contains(&kind) {
378	        return "_LIT".to_string();
379	    }
380	    let start = node.start_byte();
381	    let end = node.end_byte();
382	    source[start..end].to_string()
383	}
384	
385	pub fn build_normalized_subtree(
386	    node: tree_sitter::Node,
387	    source: &str,
388	    config: &LangConfig,
389	) -> String {
390	    if node.child_count() == 0 {
391	        return normalize_node_text(node, source, config);
392	    }
393	    let mut parts = vec![format!("({}:", node.kind())];
394	    let mut cursor = node.walk();
395	    for child in node.children(&mut cursor) {
396	        parts.push(build_normalized_subtree(child, source, config));
397	    }
398	    parts.push(")".to_string());
399	    parts.join("")
400	}
