402	fn hash_str(s: &str) -> u64 {
403	    use std::hash::{Hash, Hasher};
404	    let mut h = std::collections::hash_map::DefaultHasher::new();
405	    s.hash(&mut h);
406	    h.finish()
407	}
408	
409	fn collect_subtree_hashes(node: tree_sitter::Node, source: &str, config: &LangConfig) -> Vec<u64> {
410	    let mut hashes = Vec::new();
411	    collect_hashes_recursive(node, source, config, &mut hashes);
412	    hashes.sort_unstable();
413	    hashes
414	}
415	
416	fn collect_hashes_recursive(
417	    node: tree_sitter::Node,
418	    source: &str,
419	    config: &LangConfig,
420	    hashes: &mut Vec<u64>,
421	) {
422	    let subtree = build_normalized_subtree(node, source, config);
423	    hashes.push(hash_str(&subtree));
424	    let mut cursor = node.walk();
425	    for child in node.children(&mut cursor) {
426	        collect_hashes_recursive(child, source, config, hashes);
427	    }
428	}
