18	pub fn is_builtin_excluded(path: &Path) -> bool {
19	    path.components().any(|c| {
20	        if let Component::Normal(name) = c {
21	            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
22	        } else {
23	            false
24	        }
25	    })
26	}
