73	pub fn is_rust_file(path: &Path) -> bool {
74	    path.extension().and_then(|e| e.to_str()) == Some("rs")
75	}
76	
77	pub fn is_supported_file(path: &Path) -> bool {
78	    detect_lang(path).is_some()
79	}
80	
81	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
82	    if exclude_set.is_empty() {
83	        return false;
84	    }
85	    exclude_set.is_match(path)
86	}
