88	/// Returns whether a file should be scanned.
89	/// When force_lang is Some, every non-excluded, non-builtin-excluded file is scanned.
90	/// When force_lang is None, only files with recognized extensions are scanned.
91	pub fn should_scan_file(
92	    path: &Path,
93	    exclude_set: &GlobSet,
94	    git_ignored: &dyn Fn(&Path) -> bool,
95	    force_lang: Option<Lang>,
96	) -> bool {
97	    if is_builtin_excluded(path) || should_skip(path, exclude_set) || git_ignored(path) {
98	        return false;
99	    }
100	    match force_lang {
101	        Some(_) => true,
102	        None => is_supported_file(path),
103	    }
104	}
