106	pub fn collect_all_functions(
107	    paths: &[String],
108	    exclude_set: &GlobSet,
109	    force_lang: Option<Lang>,
110	) -> (Vec<FunctionInfo>, Vec<String>) {
111	    let mut functions: Vec<FunctionInfo> = Vec::new();
112	    let mut errors: Vec<String> = Vec::new();
113	    for path_str in paths {
114	        let path = Path::new(path_str);
115	        if !path.exists() {
116	            errors.push(format!("path does not exist: {}", path_str));
117	        } else {
118	            collect_functions_from_path(path, exclude_set, force_lang, &mut functions, &mut errors);
119	        }
120	    }
121	    (functions, errors)
122	}
123	
124	pub fn collect_functions_from_path(
125	    path: &Path,
126	    exclude_set: &GlobSet,
127	    force_lang: Option<Lang>,
128	    functions: &mut Vec<FunctionInfo>,
129	    errors: &mut Vec<String>,
130	) {
131	    if path.is_file() {
132	        collect_from_single_file(path, exclude_set, force_lang, functions, errors);
133	    } else {
134	        collect_from_directory(path, exclude_set, force_lang, functions, errors);
135	    }
136	}
137	
138	pub fn collect_from_single_file(
139	    path: &Path,
140	    exclude_set: &GlobSet,
141	    force_lang: Option<Lang>,
142	    functions: &mut Vec<FunctionInfo>,
143	    errors: &mut Vec<String>,
144	) {
145	    if should_scan_file(path, exclude_set, &is_git_ignored, force_lang) {
146	        let lang = force_lang.or_else(|| detect_lang(path)).unwrap();
147	        process_file(path, lang, functions, errors);
148	    }
149	}
150	
151	fn process_entry(
152	    entry: Result<walkdir::DirEntry, walkdir::Error>,
153	    exclude_set: &GlobSet,
154	    force_lang: Option<Lang>,
155	    functions: &mut Vec<FunctionInfo>,
156	    errors: &mut Vec<String>,
157	) {
158	    match entry {
159	        Ok(e)
160	            if e.file_type().is_file()
161	                && should_scan_file(e.path(), exclude_set, &is_git_ignored, force_lang) =>
162	        {
163	            let lang = force_lang.or_else(|| detect_lang(e.path())).unwrap();
164	            process_file(e.path(), lang, functions, errors);
165	        }
166	        Ok(_) => {}
167	        Err(err) => errors.push(format!("walk error: {}", err)),
168	    }
169	}
170	
171	pub fn collect_from_directory(
172	    path: &Path,
173	    exclude_set: &GlobSet,
174	    force_lang: Option<Lang>,
175	    functions: &mut Vec<FunctionInfo>,
176	    errors: &mut Vec<String>,
177	) {
178	    let walker = WalkDir::new(path)
179	        .sort_by_file_name()
180	        .into_iter()
181	        .filter_entry(|e| !e.file_type().is_dir() || !is_builtin_excluded(e.path()));
182	    for entry in walker {
183	        process_entry(entry, exclude_set, force_lang, functions, errors);
184	    }
185	}
186	
187	pub fn process_file(
188	    path: &Path,
189	    lang: Lang,
190	    functions: &mut Vec<FunctionInfo>,
191	    errors: &mut Vec<String>,
192	) {
193	    let source = match std::fs::read_to_string(path) {
194	        Ok(s) => s,
195	        Err(e) => {
196	            errors.push(format!("cannot read {}: {}", path.display(), e));
197	            return;
198	        }
199	    };
200	
201	    let config: &LangConfig = lang_config(lang);
202	    match parse_source_tree_for(&source, lang) {
203	        Ok(tree) => {
204	            let file_str = path.to_string_lossy().to_string();
205	            extract_functions_with_config(tree.root_node(), &source, &file_str, config, functions);
206	        }
207	        Err(msg) => {
208	            errors.push(format!("{} in {}", msg, path.display()));
209	        }
210	    }
211	}
